#include <bits/stdc++.h>
using namespace std;
int n,m;
const int N = 5e3+5;
const int M = 1e4+5;
int End[M], Last[N], Next[M], Len[M], e;
void add_edge (int x, int y, int z) {
	End[++e] = y;
	Next[e] = Last[x];
	Last[x] = e;
	Len[e] = z;
}
int dis[N], cnt[N];
queue <int> q;
bool inq[N];
bool spfa (int s) {
	for (int i = 0; i <= n; i++) {
		dis[i] = -1e9; 
	}
	dis[s] = 0;
	q.push (s);
	inq[s] = true;
	cnt[s]++;
	while (q.size()) {
		int x = q.front();
		q.pop();
		inq[x] = false;
		for(int i = Last[x]; i; i = Next[i]) {
			int y = End[i];
			if (dis[y] < dis[x] + Len[i]) {
				dis[y] = dis[x] + Len[i];
				if (!inq[y]) {
					q.push (y);
					inq[y] = true;
					cnt[y]++;
					if (cnt[y] > n + 1) {
						return false;
					}
				}
			}
		}
	}
	return true;
}
int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		add_edge (0, i, 0);
	}
	for (int i = 1; i <= m; i++) {
		int x, y, z;
		cin >> x >> y >> z;
		add_edge (x, y, -z);
	}
	if (spfa (0)) {
		for (int i = 1; i <= n; i++) {
			printf ("%d%c", dis[i], i < n ? ' ' : '\n');
		}
	} else {
		cout << "NO\n";
	}
	return 0;
}
